import Image from 'next/image'

export interface GridWithMediaTopProps {
  media: {
    url: string
    alt: string
  }
  items: {
    title: string
    description: string
  }[]
}

export function GridWithMediaTop({
  media,
  items,
}: Readonly<GridWithMediaTopProps>) {
  return (
    <div className="space-y-8">
      {media && (
        <div className="relative max-h-140 min-h-96 w-full overflow-hidden rounded-lg">
          <Image
            src={media.url}
            alt={media.alt ?? 'Grid With Media Top'}
            className="h-full w-full object-cover"
            fill
            unoptimized
          />
        </div>
      )}

      {items && items.length > 0 && (
        <ul className="m-0 grid list-none grid-cols-1 gap-6 p-0 md:grid-cols-2 lg:grid-cols-3">
          {items.map((item, index) => (
            <li key={`${item.title}-${index}`} className="flex flex-col gap-2">
              {item.title && (
                <h3 className="text-lg font-medium">{item.title}</h3>
              )}
              {item.description && (
                <p className="text-muted-foreground max-w-md text-sm">
                  {item.description}
                </p>
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  )
}

import {
  GridWithMediaTop,
  type GridWithMediaTopProps,
} from './grid-with-media-top'

export function GridWithMediaTopExample() {
  const values = {
    media: {
      url: 'https://images.unsplash.com/photo-1765871319901-0aaafe3f1a2a?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
      alt: 'Section hero image',
    },
    items: [
      {
        title: 'Lightweight',
        description: 'Only what you need. No bloat, no lock-in.',
      },
      {
        title: 'Customizable',
        description: 'Copy, tweak, and own. Built to fit your design system.',
      },
      {
        title: 'Ready to ship',
        description: 'Stable, accessible, and ready for production.',
      },
    ],
  } satisfies GridWithMediaTopProps

  return <GridWithMediaTop media={values.media} items={values.items} />
}
